// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import { ReceiverTemplate } from "./ReceiverTemplate.sol";
import { ConditionalTokens } from "./ConditionalTokens.sol";

/**
 * @title AiCTFAdapter
 * @notice Oracle adapter that resolves Conditional Token Framework markets via Chainlink CRE + Gemini AI.
 *
 * @dev Architecture:
 *  1. `initializeMarket()` prepares a CTF condition and emits `MarketInitialized` (triggers CRE).
 *  2. CRE detects the event, calls Gemini AI, then submits `onReport(metadata, report)`.
 *  3. The adapter starts a `disputeWindow` timer and emits `ResolutionProposed`.
 *  4. After the window, anyone calls `finalizeResolution()` to call `ctf.reportPayouts()`.
 *  5. Before the window elapses:
 *     - The contract owner can `adminOverride()` to replace the proposed payouts.
 *     - The multisig (if set) can call `multisigOverride()` which requires M-of-N signers.
 *
 * Key invariants:
 *  - AiCTFAdapter is the sole oracle address in every `prepareCondition()` call.
 *  - No market string metadata is stored on-chain — only the IPFS CID via events.
 *  - The dispute window is sovereign: no finalization until it elapses.
 */
contract AiCTFAdapter is ReceiverTemplate {
    ////////////////////////////////////////////////////
    // Types
    ////////////////////////////////////////////////////

    enum MarketStatus { Uninitialized, Active, Proposed, Resolved }

    struct MarketQuestion {
        uint256 resolutionTime;     // Target resolution timestamp
        uint256 proposedAt;         // Timestamp when CRE submitted a proposal
        uint256[] proposedPayouts;  // Payouts proposed by AI
        uint256 outcomeCount;       // Number of outcome slots
        MarketStatus status;
        bool multisigApproved;      // Set to true once multisig threshold is met
    }

    ////////////////////////////////////////////////////
    // State
    ////////////////////////////////////////////////////

    /// @notice The Gnosis Conditional Token Framework contract
    ConditionalTokens public immutable ctf;

    /// @notice Duration of the dispute window after a resolution is proposed
    uint256 public disputeWindow;

    /// @notice Minimum number of multisig signers required to approve an override
    uint256 public multisigThreshold;

    /// @notice List of authorised multisig signers
    address[] public multisigSigners;

    /// @notice questionId → MarketQuestion
    mapping(bytes32 => MarketQuestion) public questions;

    /// @notice questionId → signer → has approved the pending proposal override
    mapping(bytes32 => mapping(address => bool)) public multisigApprovals;

    /// @notice questionId → current multisig approval count for a proposed override
    mapping(bytes32 => uint256) public multisigApprovalCount;

    /// @notice Address of the MarketRegistry (only it may call initializeMarket)
    address public registry;

    ////////////////////////////////////////////////////
    // Events
    ////////////////////////////////////////////////////

    event MarketInitialized(
        bytes32 indexed questionId,
        string  ipfsCid,
        uint256 outcomeCount,
        uint256 resolutionTime
    );

    event ResolutionProposed(
        bytes32 indexed questionId,
        uint256[] payouts,
        uint256 disputeWindowEnd
    );

    event ResolutionProposalReplaced(
        bytes32 indexed questionId,
        uint256[] newPayouts,
        address  replacedBy
    );

    event MarketResolved(
        bytes32 indexed questionId,
        uint256[] payouts
    );

    event MultisigOverrideApproved(
        bytes32 indexed questionId,
        address indexed signer,
        uint256 approvalsNow,
        uint256 threshold
    );

    event MultisigThresholdUpdated(uint256 newThreshold);
    event MultisigSignersUpdated(address[] newSigners);
    event DisputeWindowUpdated(uint256 newWindow);
    event RegistryUpdated(address newRegistry);

    ////////////////////////////////////////////////////
    // Errors
    ////////////////////////////////////////////////////

    error NotRegistry();
    error AlreadyInitialized();
    error NotInitialized();
    error AlreadyResolved();
    error DisputeWindowActive();
    error DisputeWindowExpired();
    error NoProposalPending();
    error NotMultisigSigner();
    error AlreadyApproved();
    error ThresholdNotMet();
    error InvalidPayouts();
    error InvalidDisputeWindow();
    error InvalidThreshold();
    error ZeroOutcomeCount();

    ////////////////////////////////////////////////////
    // Modifiers
    ////////////////////////////////////////////////////

    modifier onlyRegistry() {
        if (msg.sender != registry) revert NotRegistry();
        _;
    }

    ////////////////////////////////////////////////////
    // Constructor
    ////////////////////////////////////////////////////

    /**
     * @param _ctf              Address of the deployed ConditionalTokens contract.
     * @param _forwarderAddress Chainlink CRE forwarder (only address allowed to call onReport).
     * @param _disputeWindow    Seconds after a proposal before it can be finalized.
     * @param _multisigSigners  Initial list of multisig signer addresses.
     * @param _multisigThreshold Minimum approvals required (must be ≤ _multisigSigners.length).
     */
    constructor(
        address _ctf,
        address _forwarderAddress,
        uint256 _disputeWindow,
        address[] memory _multisigSigners,
        uint256 _multisigThreshold
    ) ReceiverTemplate(_forwarderAddress) {
        if (_disputeWindow == 0) revert InvalidDisputeWindow();
        if (_multisigSigners.length > 0 && (_multisigThreshold == 0 || _multisigThreshold > _multisigSigners.length)) {
            revert InvalidThreshold();
        }
        ctf = ConditionalTokens(_ctf);
        disputeWindow = _disputeWindow;
        multisigSigners = _multisigSigners;
        multisigThreshold = _multisigThreshold;
    }

    ////////////////////////////////////////////////////
    // Initialisation (called by MarketRegistry)
    ////////////////////////////////////////////////////

    /**
     * @notice Registers a new prediction market with the CTF and Chainlink CRE.
     * @dev Only callable by the MarketRegistry contract.
     *      Emits MarketInitialized — this event is the CRE log trigger.
     * @param questionId      keccak256(abi.encodePacked(ipfsCid))
     * @param ipfsCid         IPFS CID of the JSON metadata — NOT stored on-chain, emitted only.
     * @param outcomeCount    Number of outcome slots (2 for binary markets).
     * @param resolutionTime  Unix timestamp when CRE should attempt resolution.
     */
    function initializeMarket(
        bytes32 questionId,
        string calldata ipfsCid,
        uint256 outcomeCount,
        uint256 resolutionTime
    ) external onlyRegistry {
        if (outcomeCount < 2) revert ZeroOutcomeCount();
        MarketQuestion storage q = questions[questionId];
        if (q.status != MarketStatus.Uninitialized) revert AlreadyInitialized();

        // Prepare the condition on the CTF — no new contract deployed
        ctf.prepareCondition(address(this), questionId, outcomeCount);

        q.resolutionTime  = resolutionTime;
        q.outcomeCount    = outcomeCount;
        q.status          = MarketStatus.Active;

        // CRE listens for this event to schedule the AI resolution job
        emit MarketInitialized(questionId, ipfsCid, outcomeCount, resolutionTime);
    }

    ////////////////////////////////////////////////////
    // CRE Callback (called by Chainlink Forwarder)
    ////////////////////////////////////////////////////

    /**
     * @notice Internal hook invoked by ReceiverTemplate.onReport() after forwarder validation.
     * @dev Report format: abi.encode(bytes32 questionId, uint256[] payouts)
     *      Starts the dispute window; finalization is via finalizeResolution().
     */
    function _processReport(bytes calldata report) internal override {
        (bytes32 questionId, uint256[] memory payouts) = abi.decode(report, (bytes32, uint256[]));

        MarketQuestion storage q = questions[questionId];
        if (q.status == MarketStatus.Uninitialized) revert NotInitialized();
        if (q.status == MarketStatus.Resolved) revert AlreadyResolved();
        if (!_isValidPayouts(payouts, q.outcomeCount)) revert InvalidPayouts();

        // Replace any existing proposal (CRE may resubmit after a dispute)
        q.proposedPayouts = payouts;
        q.proposedAt      = block.timestamp;
        q.status          = MarketStatus.Proposed;
        // Reset multisig approval state for the new proposal
        _resetMultisigApprovals(questionId);

        emit ResolutionProposed(questionId, payouts, block.timestamp + disputeWindow);
    }

    ////////////////////////////////////////////////////
    // Finalization (permissionless after dispute window)
    ////////////////////////////////////////////////////

    /**
     * @notice Finalizes a proposed resolution after the dispute window elapses.
     * @dev Permissionless — anyone can call once the window is over.
     * @param questionId The market to finalize.
     */
    function finalizeResolution(bytes32 questionId) external {
        MarketQuestion storage q = questions[questionId];
        if (q.status == MarketStatus.Uninitialized) revert NotInitialized();
        if (q.status != MarketStatus.Proposed) revert NoProposalPending();
        if (q.status == MarketStatus.Resolved) revert AlreadyResolved();
        if (block.timestamp < q.proposedAt + disputeWindow) revert DisputeWindowActive();

        _resolve(questionId, q);
    }

    ////////////////////////////////////////////////////
    // Owner Override (within dispute window only)
    ////////////////////////////////////////////////////

    /**
     * @notice Allows the contract owner to replace a pending CRE proposal during the dispute window.
     * @dev NOT available after the dispute window has elapsed.
     * @param questionId  The market to override.
     * @param payouts     Corrected payout array.
     */
    function adminOverride(bytes32 questionId, uint256[] calldata payouts) external onlyOwner {
        MarketQuestion storage q = questions[questionId];
        if (q.status == MarketStatus.Uninitialized) revert NotInitialized();
        if (q.status != MarketStatus.Proposed) revert NoProposalPending();
        if (q.status == MarketStatus.Resolved) revert AlreadyResolved();
        if (block.timestamp >= q.proposedAt + disputeWindow) revert DisputeWindowExpired();
        if (!_isValidPayouts(payouts, q.outcomeCount)) revert InvalidPayouts();

        q.proposedPayouts = payouts;
        q.proposedAt      = block.timestamp; // Reset window with new proposal
        _resetMultisigApprovals(questionId);

        emit ResolutionProposalReplaced(questionId, payouts, msg.sender);
        emit ResolutionProposed(questionId, payouts, block.timestamp + disputeWindow);
    }

    ////////////////////////////////////////////////////
    // Multisig Override (within dispute window only)
    ////////////////////////////////////////////////////

    /**
     * @notice A multisig signer approves the current pending proposal override.
     * @dev Once `multisigThreshold` approvals are collected, the resolution is finalized
     *      immediately — bypassing the remaining dispute window.
     *      Only available while the dispute window is still active.
     * @param questionId  The market question ID.
     * @param payouts     The new payout array all signers are approving.
     *                    All signers must supply identical payouts; any mismatch resets approvals.
     */
    function multisigOverride(bytes32 questionId, uint256[] calldata payouts) external {
        MarketQuestion storage q = questions[questionId];
        if (q.status == MarketStatus.Uninitialized) revert NotInitialized();
        if (q.status != MarketStatus.Proposed) revert NoProposalPending();
        if (q.status == MarketStatus.Resolved) revert AlreadyResolved();
        if (block.timestamp >= q.proposedAt + disputeWindow) revert DisputeWindowExpired();
        if (!_isMultisigSigner(msg.sender)) revert NotMultisigSigner();
        if (multisigApprovals[questionId][msg.sender]) revert AlreadyApproved();
        if (!_isValidPayouts(payouts, q.outcomeCount)) revert InvalidPayouts();

        // If this signer's payouts differ from the current proposed payouts, reset approvals
        if (!_payoutsMatch(payouts, q.proposedPayouts)) {
            q.proposedPayouts = payouts;
            q.proposedAt      = block.timestamp;
            _resetMultisigApprovals(questionId);
            emit ResolutionProposalReplaced(questionId, payouts, msg.sender);
        }

        multisigApprovals[questionId][msg.sender] = true;
        multisigApprovalCount[questionId]++;

        emit MultisigOverrideApproved(questionId, msg.sender, multisigApprovalCount[questionId], multisigThreshold);

        // Finalise immediately if threshold reached
        if (multisigApprovalCount[questionId] >= multisigThreshold) {
            q.multisigApproved = true;
            _resolve(questionId, q);
        }
    }

    ////////////////////////////////////////////////////
    // Internal Helpers
    ////////////////////////////////////////////////////

    function _resolve(bytes32 questionId, MarketQuestion storage q) internal {
        q.status = MarketStatus.Resolved;
        // AiCTFAdapter is the oracle — msg.sender does not matter here, ctf checks address(this)
        ctf.reportPayouts(questionId, q.proposedPayouts);
        emit MarketResolved(questionId, q.proposedPayouts);
    }

    function _isValidPayouts(uint256[] memory payouts, uint256 outcomeCount) internal pure returns (bool) {
        if (payouts.length != outcomeCount) return false;
        uint256 sum = 0;
        for (uint256 i = 0; i < payouts.length; i++) sum += payouts[i];
        return sum > 0;
    }

    function _payoutsMatch(uint256[] calldata a, uint256[] storage b) internal view returns (bool) {
        if (a.length != b.length) return false;
        for (uint256 i = 0; i < a.length; i++) {
            if (a[i] != b[i]) return false;
        }
        return true;
    }

    function _isMultisigSigner(address addr) internal view returns (bool) {
        for (uint256 i = 0; i < multisigSigners.length; i++) {
            if (multisigSigners[i] == addr) return true;
        }
        return false;
    }

    function _resetMultisigApprovals(bytes32 questionId) internal {
        for (uint256 i = 0; i < multisigSigners.length; i++) {
            multisigApprovals[questionId][multisigSigners[i]] = false;
        }
        multisigApprovalCount[questionId] = 0;
        questions[questionId].multisigApproved = false;
    }

    ////////////////////////////////////////////////////
    // Admin Configuration
    ////////////////////////////////////////////////////

    /// @notice Only the deployer (owner) can set the registry address.
    function setRegistry(address _registry) external onlyOwner {
        registry = _registry;
        emit RegistryUpdated(_registry);
    }

    function setDisputeWindow(uint256 _window) external onlyOwner {
        if (_window == 0) revert InvalidDisputeWindow();
        disputeWindow = _window;
        emit DisputeWindowUpdated(_window);
    }

    function setMultisigSigners(address[] calldata _signers, uint256 _threshold) external onlyOwner {
        if (_signers.length > 0 && (_threshold == 0 || _threshold > _signers.length)) revert InvalidThreshold();
        multisigSigners = _signers;
        multisigThreshold = _threshold;
        emit MultisigSignersUpdated(_signers);
        emit MultisigThresholdUpdated(_threshold);
    }

    ////////////////////////////////////////////////////
    // View Functions
    ////////////////////////////////////////////////////

    function getQuestion(bytes32 questionId) external view returns (MarketQuestion memory) {
        return questions[questionId];
    }

    function getDisputeWindowEnd(bytes32 questionId) external view returns (uint256) {
        MarketQuestion storage q = questions[questionId];
        if (q.status != MarketStatus.Proposed) return 0;
        return q.proposedAt + disputeWindow;
    }

    function isMultisigSigner(address addr) external view returns (bool) {
        return _isMultisigSigner(addr);
    }

    function getMultisigSigners() external view returns (address[] memory) {
        return multisigSigners;
    }
}

contracts/AutoFinalizerUpkeep.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import { AiCTFAdapter } from "./AiCTFAdapter.sol";
import { MarketRegistry } from "./MarketRegistry.sol";

/**
 * @title AutoFinalizerUpkeep
 * @notice Chainlink Automation Upkeep contract to automatically finalize resolutions
 *         once their dispute window has elapsed.
 */
contract AutoFinalizerUpkeep {
    AiCTFAdapter public immutable adapter;
    MarketRegistry public immutable registry;

    constructor(address _adapter, address _registry) {
        adapter = AiCTFAdapter(_adapter);
        registry = MarketRegistry(_registry);
    }

    /**
     * @notice Chainlink Automation checkUpkeep
     * @dev Iterates through all active markets in the registry, checks if they are
     *      in the 'Proposed' state, and if the dispute window has elapsed.
     */
    function checkUpkeep(bytes calldata /* checkData */) external view returns (bool upkeepNeeded, bytes memory performData) {
        bytes32[] memory allMarkets = registry.getAllMarkets();

        for (uint256 i = 0; i < allMarkets.length; i++) {
            bytes32 qId = allMarkets[i];
            AiCTFAdapter.MarketQuestion memory q = adapter.getQuestion(qId);

            // Status 2 is 'Proposed'
            if (uint256(q.status) == 2) {
                uint256 windowEnd = q.proposedAt + adapter.disputeWindow();
                if (block.timestamp >= windowEnd) {
                    // Found a market that needs finalization
                    return (true, abi.encode(qId));
                }
            }
        }

        return (false, "");
    }

    /**
     * @notice Chainlink Automation performUpkeep
     * @dev Calls finalizeResolution on the adapter for the encoded questionId.
     */
    function performUpkeep(bytes calldata performData) external {
        bytes32 questionId = abi.decode(performData, (bytes32));

        // Re-validate to ensure it still needs finalization
        AiCTFAdapter.MarketQuestion memory q = adapter.getQuestion(questionId);
        require(uint256(q.status) == 2, "Market not in Proposed state");
        require(block.timestamp >= q.proposedAt + adapter.disputeWindow(), "Dispute window not elapsed");

        // Finalize the resolution (this will call ctf.reportPayouts)
        adapter.finalizeResolution(questionId);
    }
}

contracts/ConditionalTokens.sol.content:
// SPDX-License-Identifier: LGPL-3.0
// Adapted from Gnosis Conditional Token Framework for Solidity ^0.8.0
// Original: https://github.com/gnosis/conditional-tokens-contracts
pragma solidity ^0.8.0;

import { IERC20 } from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import { ERC1155 } from "@openzeppelin/contracts/token/ERC1155/ERC1155.sol";

/**
 * @title ConditionalTokens
 * @notice Core Gnosis Conditional Token Framework — markets are conditionIds, not deployed contracts.
 * @dev Ported from Gnosis CTF (^0.5.1) to Solidity ^0.8.0 (SafeMath removed, native overflow).
 * ERC-1155 position IDs are derived deterministically from collateral + conditionId + indexSet.
 */
contract ConditionalTokens is ERC1155 {
    /////////////////////////////
    // Events
    /////////////////////////////

    /// @dev Emitted on prepareCondition()
    event ConditionPreparation(
        bytes32 indexed conditionId,
        address indexed oracle,
        bytes32 indexed questionId,
        uint256 outcomeSlotCount
    );

    /// @dev Emitted on reportPayouts()
    event ConditionResolution(
        bytes32 indexed conditionId,
        address indexed oracle,
        bytes32 indexed questionId,
        uint256 outcomeSlotCount,
        uint256[] payoutNumerators
    );

    /// @dev Emitted on splitPosition()
    event PositionSplit(
        address indexed stakeholder,
        IERC20 collateralToken,
        bytes32 indexed parentCollectionId,
        bytes32 indexed conditionId,
        uint256[] partition,
        uint256 amount
    );

    /// @dev Emitted on mergePositions()
    event PositionsMerge(
        address indexed stakeholder,
        IERC20 collateralToken,
        bytes32 indexed parentCollectionId,
        bytes32 indexed conditionId,
        uint256[] partition,
        uint256 amount
    );

    event PayoutRedemption(
        address indexed redeemer,
        IERC20 indexed collateralToken,
        bytes32 indexed parentCollectionId,
        bytes32 conditionId,
        uint256[] indexSets,
        uint256 payout
    );

    /////////////////////////////
    // State
    /////////////////////////////

    /// @notice Payout numerators per conditionId. Empty = not prepared.
    mapping(bytes32 => uint256[]) public payoutNumerators;

    /// @notice Payout denominator; nonzero = condition resolved.
    mapping(bytes32 => uint256) public payoutDenominator;

    constructor() ERC1155("") {}

    /////////////////////////////
    // Core Functions
    /////////////////////////////

    /**
     * @notice Registers a new condition (market) on-chain.
     * @param oracle         The address that will call reportPayouts() for this condition.
     * @param questionId     Unique question identifier (keccak256 of IPFS CID).
     * @param outcomeSlotCount Number of outcomes (2 for binary YES/NO).
     */
    function prepareCondition(address oracle, bytes32 questionId, uint256 outcomeSlotCount) external {
        require(outcomeSlotCount <= 256, "CTF: too many outcome slots");
        require(outcomeSlotCount > 1, "CTF: need more than one outcome slot");
        bytes32 conditionId = getConditionId(oracle, questionId, outcomeSlotCount);
        require(payoutNumerators[conditionId].length == 0, "CTF: condition already prepared");
        payoutNumerators[conditionId] = new uint256[](outcomeSlotCount);
        emit ConditionPreparation(conditionId, oracle, questionId, outcomeSlotCount);
    }

    /**
     * @notice Called by the oracle to resolve a condition.
     * @param questionId  The question ID the oracle is answering.
     * @param payouts     Array of payout numerators per outcome slot.
     */
    function reportPayouts(bytes32 questionId, uint256[] calldata payouts) external {
        uint256 outcomeSlotCount = payouts.length;
        require(outcomeSlotCount > 1, "CTF: need more than one outcome slot");
        bytes32 conditionId = getConditionId(msg.sender, questionId, outcomeSlotCount);
        require(payoutNumerators[conditionId].length == outcomeSlotCount, "CTF: condition not prepared");
        require(payoutDenominator[conditionId] == 0, "CTF: already resolved");

        uint256 den = 0;
        for (uint256 i = 0; i < outcomeSlotCount; i++) {
            uint256 num = payouts[i];
            den += num;
            require(payoutNumerators[conditionId][i] == 0, "CTF: numerator already set");
            payoutNumerators[conditionId][i] = num;
        }
        require(den > 0, "CTF: all-zero payout");
        payoutDenominator[conditionId] = den;
        emit ConditionResolution(conditionId, msg.sender, questionId, outcomeSlotCount, payoutNumerators[conditionId]);
    }

    /**
     * @notice Splits a collateral position into outcome positions.
     * @param collateralToken  ERC-20 used as collateral (e.g. USDC).
     * @param parentCollectionId  bytes32(0) for root positions.
     * @param conditionId      The condition to split on.
     * @param partition        Array of disjoint index sets.
     * @param amount           Amount of collateral to lock.
     */
    function splitPosition(
        IERC20 collateralToken,
        bytes32 parentCollectionId,
        bytes32 conditionId,
        uint256[] calldata partition,
        uint256 amount
    ) external {
        require(partition.length > 1, "CTF: need at least 2 partition elements");
        uint256 outcomeSlotCount = payoutNumerators[conditionId].length;
        require(outcomeSlotCount > 0, "CTF: condition not prepared");

        uint256 fullIndexSet = (1 << outcomeSlotCount) - 1;
        uint256 freeIndexSet = fullIndexSet;
        uint256[] memory positionIds = new uint256[](partition.length);
        uint256[] memory amounts = new uint256[](partition.length);

        for (uint256 i = 0; i < partition.length; i++) {
            uint256 indexSet = partition[i];
            require(indexSet > 0 && indexSet < fullIndexSet, "CTF: invalid index set");
            require((indexSet & freeIndexSet) == indexSet, "CTF: partition not disjoint");
            freeIndexSet ^= indexSet;
            positionIds[i] = getPositionId(collateralToken, getCollectionId(parentCollectionId, conditionId, indexSet));
            amounts[i] = amount;
        }

        if (freeIndexSet == 0) {
            if (parentCollectionId == bytes32(0)) {
                require(collateralToken.transferFrom(msg.sender, address(this), amount), "CTF: collateral transfer failed");
            } else {
                _burn(msg.sender, getPositionId(collateralToken, parentCollectionId), amount);
            }
        } else {
            _burn(
                msg.sender,
                getPositionId(
                    collateralToken,
                    getCollectionId(parentCollectionId, conditionId, fullIndexSet ^ freeIndexSet)
                ),
                amount
            );
        }

        _mintBatch(msg.sender, positionIds, amounts, "");
        emit PositionSplit(msg.sender, collateralToken, parentCollectionId, conditionId, partition, amount);
    }

    /**
     * @notice Merges outcome positions back into collateral.
     */
    function mergePositions(
        IERC20 collateralToken,
        bytes32 parentCollectionId,
        bytes32 conditionId,
        uint256[] calldata partition,
        uint256 amount
    ) external {
        require(partition.length > 1, "CTF: need at least 2 partition elements");
        uint256 outcomeSlotCount = payoutNumerators[conditionId].length;
        require(outcomeSlotCount > 0, "CTF: condition not prepared");

        uint256 fullIndexSet = (1 << outcomeSlotCount) - 1;
        uint256 freeIndexSet = fullIndexSet;
        uint256[] memory positionIds = new uint256[](partition.length);
        uint256[] memory amounts = new uint256[](partition.length);

        for (uint256 i = 0; i < partition.length; i++) {
            uint256 indexSet = partition[i];
            require(indexSet > 0 && indexSet < fullIndexSet, "CTF: invalid index set");
            require((indexSet & freeIndexSet) == indexSet, "CTF: partition not disjoint");
            freeIndexSet ^= indexSet;
            positionIds[i] = getPositionId(collateralToken, getCollectionId(parentCollectionId, conditionId, indexSet));
            amounts[i] = amount;
        }

        _burnBatch(msg.sender, positionIds, amounts);

        if (freeIndexSet == 0) {
            if (parentCollectionId == bytes32(0)) {
                require(collateralToken.transfer(msg.sender, amount), "CTF: collateral return failed");
            } else {
                _mint(msg.sender, getPositionId(collateralToken, parentCollectionId), amount, "");
            }
        } else {
            _mint(
                msg.sender,
                getPositionId(
                    collateralToken,
                    getCollectionId(parentCollectionId, conditionId, fullIndexSet ^ freeIndexSet)
                ),
                amount,
                ""
            );
        }

        emit PositionsMerge(msg.sender, collateralToken, parentCollectionId, conditionId, partition, amount);
    }

    /**
     * @notice Redeems winning outcome positions for collateral after resolution.
     */
    function redeemPositions(
        IERC20 collateralToken,
        bytes32 parentCollectionId,
        bytes32 conditionId,
        uint256[] calldata indexSets
    ) external {
        uint256 den = payoutDenominator[conditionId];
        require(den > 0, "CTF: condition not resolved");
        uint256 outcomeSlotCount = payoutNumerators[conditionId].length;
        require(outcomeSlotCount > 0, "CTF: condition not prepared");

        uint256 totalPayout = 0;
        uint256 fullIndexSet = (1 << outcomeSlotCount) - 1;

        for (uint256 i = 0; i < indexSets.length; i++) {
            uint256 indexSet = indexSets[i];
            require(indexSet > 0 && indexSet < fullIndexSet, "CTF: invalid index set");
            uint256 positionId = getPositionId(
                collateralToken,
                getCollectionId(parentCollectionId, conditionId, indexSet)
            );

            uint256 payoutNumerator = 0;
            for (uint256 j = 0; j < outcomeSlotCount; j++) {
                if (indexSet & (1 << j) != 0) {
                    payoutNumerator += payoutNumerators[conditionId][j];
                }
            }

            uint256 payoutStake = balanceOf(msg.sender, positionId);
            if (payoutStake > 0) {
                totalPayout += (payoutStake * payoutNumerator) / den;
                _burn(msg.sender, positionId, payoutStake);
            }
        }

        if (totalPayout > 0) {
            if (parentCollectionId == bytes32(0)) {
                require(collateralToken.transfer(msg.sender, totalPayout), "CTF: payout transfer failed");
            } else {
                _mint(msg.sender, getPositionId(collateralToken, parentCollectionId), totalPayout, "");
            }
        }

        emit PayoutRedemption(msg.sender, collateralToken, parentCollectionId, conditionId, indexSets, totalPayout);
    }

    /////////////////////////////
    // View Helpers
    /////////////////////////////

    /// @notice Returns number of outcome slots, or 0 if not prepared.
    function getOutcomeSlotCount(bytes32 conditionId) external view returns (uint256) {
        return payoutNumerators[conditionId].length;
    }

    /// @notice conditionId = keccak256(oracle, questionId, outcomeSlotCount)
    function getConditionId(address oracle, bytes32 questionId, uint256 outcomeSlotCount)
        public
        pure
        returns (bytes32)
    {
        return keccak256(abi.encodePacked(oracle, questionId, outcomeSlotCount));
    }

    /// @notice collectionId = keccak256(parentCollectionId ^ keccak256(conditionId, indexSet))
    function getCollectionId(bytes32 parentCollectionId, bytes32 conditionId, uint256 indexSet)
        public
        pure
        returns (bytes32)
    {
        return bytes32(uint256(keccak256(abi.encodePacked(conditionId, indexSet))) + uint256(parentCollectionId));
    }

    /// @notice positionId = keccak256(collateralToken, collectionId)
    function getPositionId(IERC20 collateralToken, bytes32 collectionId) public pure returns (uint256) {
        return uint256(keccak256(abi.encodePacked(collateralToken, collectionId)));
    }
}

contracts/MarketRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";
import { AiCTFAdapter } from "./AiCTFAdapter.sol";

/**
 * @title MarketRegistry
 * @notice Lightweight on-chain registry for CTF prediction markets.
 *
 * @dev Design principles:
 *  - Zero contract deployments per market. Ever.
 *  - `questionId` is the only on-chain key: keccak256(abi.encodePacked(ipfsCid)).
 *  - The ipfsCid is emitted in events only — not stored in contract storage.
 *  - A subgraph can reconstruct full market state from MarketCreated + adapter events.
 */
contract MarketRegistry is Ownable {
    ////////////////////////////////////////////////////
    // Types
    ////////////////////////////////////////////////////

    enum MarketStatus { Active, Proposed, Resolved }

    struct MarketInfo {
        uint256 outcomeCount;
        uint256 resolutionTime;
        MarketStatus status;
        bool exists;
    }

    ////////////////////////////////////////////////////
    // State
    ////////////////////////////////////////////////////

    /// @notice The AI oracle adapter (AiCTFAdapter)
    AiCTFAdapter public immutable adapter;

    /// @notice questionId → MarketInfo (lightweight — no metadata strings)
    mapping(bytes32 => MarketInfo) public markets;

    /// @notice Ordered list of all questionIds for enumeration
    bytes32[] public allMarkets;

    ////////////////////////////////////////////////////
    // Events
    ////////////////////////////////////////////////////

    /**
     * @notice Emitted when a new market is created.
     * @dev Indexed on questionId. A subgraph detects this and fetches ipfsCid to get metadata.
     * @param questionId    keccak256(abi.encodePacked(ipfsCid))
     * @param ipfsCid       IPFS CID of the metadata JSON (NOT stored on-chain)
     * @param resolutionTime Unix timestamp for AI resolution
     * @param creator       Address that called createMarket()
     */
    event MarketCreated(
        bytes32 indexed questionId,
        string  ipfsCid,
        uint256 outcomeCount,
        uint256 resolutionTime,
        address indexed creator
    );

    event MarketStatusUpdated(bytes32 indexed questionId, MarketStatus newStatus);

    ////////////////////////////////////////////////////
    // Errors
    ////////////////////////////////////////////////////

    error MarketAlreadyExists(bytes32 questionId);
    error MarketNotFound(bytes32 questionId);
    error InvalidResolutionTime();
    error InvalidOutcomeCount();
    error EmptyCid();

    ////////////////////////////////////////////////////
    // Constructor
    ////////////////////////////////////////////////////

    /**
     * @param _adapter Address of the deployed AiCTFAdapter.
     */
    constructor(address _adapter) Ownable(msg.sender) {
        adapter = AiCTFAdapter(_adapter);
    }

    ////////////////////////////////////////////////////
    // Market Creation
    ////////////////////////////////////////////////////

    /**
     * @notice Creates a new prediction market in a single transaction.
     * @dev Steps:
     *   1. Derive questionId from the IPFS CID.
     *   2. Register market metadata in local storage (no strings, only primitives).
     *   3. Call adapter.initializeMarket() → CTF prepareCondition + CRE event trigger.
     *   4. Emit MarketCreated so the subgraph / frontend can index it.
     *
     * @param ipfsCid         IPFS CID of the metadata JSON (format: "Qm..." or "bafy...").
     * @param outcomeCount    Number of outcome slots (2 for binary YES/NO).
     * @param resolutionTime  Unix timestamp when Chainlink CRE should resolve. Must be in the future.
     * @return questionId     keccak256(abi.encodePacked(ipfsCid))
     */
    function createMarket(
        string calldata ipfsCid,
        uint256 outcomeCount,
        uint256 resolutionTime
    ) external returns (bytes32 questionId) {
        if (bytes(ipfsCid).length == 0) revert EmptyCid();
        if (outcomeCount < 2) revert InvalidOutcomeCount();
        if (resolutionTime <= block.timestamp) revert InvalidResolutionTime();

        questionId = keccak256(abi.encodePacked(ipfsCid));

        if (markets[questionId].exists) revert MarketAlreadyExists(questionId);

        // Store only primitive market info — no string metadata
        markets[questionId] = MarketInfo({
            outcomeCount:   outcomeCount,
            resolutionTime: resolutionTime,
            status:         MarketStatus.Active,
            exists:         true
        });

        allMarkets.push(questionId);

        // Initialise the CTF condition + schedule CRE resolution
        adapter.initializeMarket(questionId, ipfsCid, outcomeCount, resolutionTime);

        // Emit with ipfsCid so frontend/subgraph can fetch metadata from IPFS
        emit MarketCreated(questionId, ipfsCid, outcomeCount, resolutionTime, msg.sender);
    }

    ////////////////////////////////////////////////////
    // Status Sync (called by adapter or owner)
    ////////////////////////////////////////////////////

    /**
     * @notice Syncs the registry status when the adapter resolves a market.
     * @dev The adapter emits MarketResolved; a keeper or the finalizer can call this.
     *      Alternatively, the frontend reads status directly from the adapter.
     */
    function syncStatus(bytes32 questionId) external {
        MarketInfo storage m = markets[questionId];
        if (!m.exists) revert MarketNotFound(questionId);

        AiCTFAdapter.MarketQuestion memory q = adapter.getQuestion(questionId);

        MarketStatus newStatus;
        if (uint256(q.status) == 3) {
            // AiCTFAdapter.MarketStatus.Resolved == 3
            newStatus = MarketStatus.Resolved;
        } else if (uint256(q.status) == 2) {
            newStatus = MarketStatus.Proposed;
        } else {
            newStatus = MarketStatus.Active;
        }

        if (newStatus != m.status) {
            m.status = newStatus;
            emit MarketStatusUpdated(questionId, newStatus);
        }
    }

    ////////////////////////////////////////////////////
    // View Functions
    ////////////////////////////////////////////////////

    function getMarket(bytes32 questionId) external view returns (MarketInfo memory) {
        return markets[questionId];
    }

    function getAllMarkets() external view returns (bytes32[] memory) {
        return allMarkets;
    }

    function getMarketCount() external view returns (uint256) {
        return allMarkets.length;
    }

    /**
     * @notice Returns a page of market questionIds for frontend pagination.
     */
    function getMarketsPage(uint256 offset, uint256 limit) external view returns (bytes32[] memory page) {
        uint256 total = allMarkets.length;
        if (offset >= total) return new bytes32[](0);
        uint256 end = offset + limit;
        if (end > total) end = total;
        page = new bytes32[](end - offset);
        for (uint256 i = 0; i < page.length; i++) {
            page[i] = allMarkets[offset + i];
        }
    }
}

