contracts/PredictionMarket.sol.content:
//SPDX-License-Identifier: MIT
pragma solidity >=0.8.0 <0.9.0;

import { PredictionMarketToken } from "./PredictionMarketToken.sol";
import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";

contract PredictionMarket is Ownable {
    /////////////////
    /// Errors //////
    /////////////////

    error PredictionMarket__MustProvideETHForInitialLiquidity();
    error PredictionMarket__InvalidProbability();
    error PredictionMarket__PredictionAlreadyReported();
    error PredictionMarket__OnlyOracleCanReport();
    error PredictionMarket__OwnerCannotCall();
    error PredictionMarket__PredictionNotReported();
    error PredictionMarket__InsufficientWinningTokens();
    error PredictionMarket__AmountMustBeGreaterThanZero();
    error PredictionMarket__MustSendExactETHAmount();
    error PredictionMarket__InsufficientTokenReserve(Outcome _outcome, uint256 _amountToken);
    error PredictionMarket__TokenTransferFailed();
    error PredictionMarket__ETHTransferFailed();
    error PredictionMarket__InsufficientBalance(uint256 _tradingAmount, uint256 _userBalance);
    error PredictionMarket__InsufficientAllowance(uint256 _tradingAmount, uint256 _allowance);
    error PredictionMarket__InsufficientLiquidity();
    error PredictionMarket__InvalidPercentageToLock();

    //////////////////////////
    /// State Variables //////
    //////////////////////////

    enum Outcome {
        YES,
        NO
    }

    uint256 private constant PRECISION = 1e18;

    /// Checkpoint 2 ///

    // Immutable variables (set once in constructor)
    address public immutable i_oracle;
    string public s_question;
    uint256 public immutable i_initialTokenValue;
    uint8 public immutable i_initialYesProbability;
    uint8 public immutable i_percentageLocked;

    // State variables
    uint256 public s_ethCollateral;
    uint256 public s_lpTradingRevenue;

    /// Checkpoint 3 ///

    // Token contracts
    PredictionMarketToken public immutable i_yesToken;
    PredictionMarketToken public immutable i_noToken;

    /// Checkpoint 5 ///

    // Oracle state variables
    bool public s_isReported;
    PredictionMarketToken public s_winningToken;

    /////////////////////////
    /// Events //////
    /////////////////////////

    event TokensPurchased(address indexed buyer, Outcome outcome, uint256 amount, uint256 ethAmount);
    event TokensSold(address indexed seller, Outcome outcome, uint256 amount, uint256 ethAmount);
    event WinningTokensRedeemed(address indexed redeemer, uint256 amount, uint256 ethAmount);
    event MarketReported(address indexed oracle, Outcome winningOutcome, address winningToken);
    event MarketResolved(address indexed resolver, uint256 totalEthToSend);
    event LiquidityAdded(address indexed provider, uint256 ethAmount, uint256 tokensAmount);
    event LiquidityRemoved(address indexed provider, uint256 ethAmount, uint256 tokensAmount);

    /////////////////
    /// Modifiers ///
    /////////////////

    /// Checkpoint 5 ///

    modifier predictionNotReported() {
        if (s_isReported) {
            revert PredictionMarket__PredictionAlreadyReported();
        }
        _;
    }

    /// Checkpoint 6 ///

    modifier predictionReported() {
        if (!s_isReported) {
            revert PredictionMarket__PredictionNotReported();
        }
        _;
    }

    /// Checkpoint 8 ///

    modifier amountGreaterThanZero(uint256 _amount) {
        if (_amount == 0) {
            revert PredictionMarket__AmountMustBeGreaterThanZero();
        }
        _;
    }

    modifier notOwner() {
        if (msg.sender == owner()) {
            revert PredictionMarket__OwnerCannotCall();
        }
        _;
    }

    //////////////////
    ////Constructor///
    //////////////////

    constructor(
        address _liquidityProvider,
        address _oracle,
        string memory _question,
        uint256 _initialTokenValue,
        uint8 _initialYesProbability,
        uint8 _percentageToLock
    ) payable Ownable(_liquidityProvider) {
        /// Checkpoint 2 ////
        // Validate inputs
        if (msg.value == 0) {
            revert PredictionMarket__MustProvideETHForInitialLiquidity();
        }

        if (_initialYesProbability == 0 || _initialYesProbability >= 100) {
            revert PredictionMarket__InvalidProbability();
        }

        if (_percentageToLock == 0 || _percentageToLock >= 100) {
            revert PredictionMarket__InvalidPercentageToLock();
        }

        // Set immutable variables
        i_oracle = _oracle;
        i_initialTokenValue = _initialTokenValue;
        i_initialYesProbability = _initialYesProbability;
        i_percentageLocked = _percentageToLock;

        // Set state variables
        s_question = _question;
        s_ethCollateral = msg.value;
        s_lpTradingRevenue = 0;
        s_isReported = false;

        /// Checkpoint 3 ////
        // Calculate initial token amount based on ETH sent (accounting for ERC20 decimals)
        uint256 initialTokenAmount = (msg.value * PRECISION) / _initialTokenValue;

        // Deploy the Yes and No token contracts
        i_yesToken = new PredictionMarketToken("Yes", "Y", _liquidityProvider, initialTokenAmount);
        i_noToken = new PredictionMarketToken("No", "N", _liquidityProvider, initialTokenAmount);

        // Calculate locked tokens to simulate initial probability
        uint256 lockedYes = (initialTokenAmount * _initialYesProbability * _percentageToLock * 2) / 10000;
        uint256 lockedNo = (initialTokenAmount * (100 - _initialYesProbability) * _percentageToLock * 2) / 10000;

        // Transfer locked tokens to the liquidity provider to simulate initial probability
        // The locked tokens stay with the liquidity provider (not available for trading)
        i_yesToken.transfer(_liquidityProvider, lockedYes);
        i_noToken.transfer(_liquidityProvider, lockedNo);
    }

    /////////////////
    /// Functions ///
    /////////////////

    /**
     * @notice Add liquidity to the prediction market and mint tokens
     * @dev Only the owner can add liquidity and only if the prediction is not reported
     */
    function addLiquidity() external payable onlyOwner predictionNotReported {
        //// Checkpoint 4 ////
        if (msg.value == 0) {
            revert PredictionMarket__MustProvideETHForInitialLiquidity();
        }

        // Calculate additional token amount based on ETH sent
        uint256 additionalTokenAmount = (msg.value * PRECISION) / i_initialTokenValue;

        // Mint additional tokens to the contract
        i_yesToken.mint(address(this), additionalTokenAmount);
        i_noToken.mint(address(this), additionalTokenAmount);

        // Update collateral
        s_ethCollateral += msg.value;

        emit LiquidityAdded(msg.sender, msg.value, additionalTokenAmount);
    }

    /**
     * @notice Remove liquidity from the prediction market and burn respective tokens, if you remove liquidity before prediction ends you got no share of lpReserve
     * @dev Only the owner can remove liquidity and only if the prediction is not reported
     * @param _ethToWithdraw Amount of ETH to withdraw from liquidity pool
     */
    function removeLiquidity(uint256 _ethToWithdraw) external onlyOwner predictionNotReported {
        //// Checkpoint 4 ////
        if (_ethToWithdraw == 0) {
            revert PredictionMarket__AmountMustBeGreaterThanZero();
        }

        // Calculate tokens to burn based on ETH being withdrawn
        uint256 tokensToRemove = (_ethToWithdraw * PRECISION) / i_initialTokenValue;

        // Check if contract has enough tokens to burn first
        if (tokensToRemove > i_yesToken.balanceOf(address(this))) {
            revert PredictionMarket__InsufficientTokenReserve(Outcome.YES, tokensToRemove);
        }
        if (tokensToRemove > i_noToken.balanceOf(address(this))) {
            revert PredictionMarket__InsufficientTokenReserve(Outcome.NO, tokensToRemove);
        }

        if (_ethToWithdraw > s_ethCollateral) {
            revert PredictionMarket__InsufficientLiquidity();
        }

        // Burn tokens from contract
        i_yesToken.burn(address(this), tokensToRemove);
        i_noToken.burn(address(this), tokensToRemove);

        // Update collateral
        s_ethCollateral -= _ethToWithdraw;

        // Transfer ETH to owner
        (bool success, ) = payable(msg.sender).call{value: _ethToWithdraw}("");
        if (!success) {
            revert PredictionMarket__ETHTransferFailed();
        }

        emit LiquidityRemoved(msg.sender, _ethToWithdraw, tokensToRemove);
    }

    /**
     * @notice Report the winning outcome for the prediction
     * @dev Only the oracle can report the winning outcome and only if the prediction is not reported
     * @param _winningOutcome The winning outcome (YES or NO)
     */
    function report(Outcome _winningOutcome) external predictionNotReported {
        //// Checkpoint 5 ////
        if (msg.sender != i_oracle) {
            revert PredictionMarket__OnlyOracleCanReport();
        }

        // Set the winning outcome
        s_isReported = true;

        if (_winningOutcome == Outcome.YES) {
            s_winningToken = i_yesToken;
        } else {
            s_winningToken = i_noToken;
        }

        emit MarketReported(msg.sender, _winningOutcome, address(s_winningToken));
    }

    /**
     * @notice Owner of contract can redeem winning tokens held by the contract after prediction is resolved and get ETH from the contract including LP revenue and collateral back
     * @dev Only callable by the owner and only if the prediction is resolved
     * @return ethRedeemed The amount of ETH redeemed
     */
    function resolveMarketAndWithdraw() external onlyOwner predictionReported returns (uint256 ethRedeemed) {
        /// Checkpoint 6 ////
        // Get the winning token balance held by the contract
        uint256 winningTokenBalance = s_winningToken.balanceOf(address(this));

        // Calculate ETH value of winning tokens
        uint256 winningTokenValue = (winningTokenBalance * i_initialTokenValue) / PRECISION;

        // Burn the winning tokens held by the contract
        if (winningTokenBalance > 0) {
            s_winningToken.burn(address(this), winningTokenBalance);
        }

        // Calculate total ETH to send: winning token value + trading revenue
        ethRedeemed = winningTokenValue + s_lpTradingRevenue;

        // Reset state variables
        s_ethCollateral = 0;
        s_lpTradingRevenue = 0;

        // Transfer ETH to owner
        (bool success, ) = payable(msg.sender).call{value: ethRedeemed}("");
        if (!success) {
            revert PredictionMarket__ETHTransferFailed();
        }

        emit MarketResolved(msg.sender, ethRedeemed);
    }

    /**
     * @notice Buy prediction outcome tokens with ETH, need to call priceInETH function first to get right amount of tokens to buy
     * @param _outcome The possible outcome (YES or NO) to buy tokens for
     * @param _amountTokenToBuy Amount of tokens to purchase
     */
    function buyTokensWithETH(Outcome _outcome, uint256 _amountTokenToBuy) external payable predictionNotReported amountGreaterThanZero(_amountTokenToBuy) notOwner {
        /// Checkpoint 8 ////
        // Check if contract has enough tokens to sell
        PredictionMarketToken targetToken = _outcome == Outcome.YES ? i_yesToken : i_noToken;
        if (_amountTokenToBuy > targetToken.balanceOf(address(this))) {
            revert PredictionMarket__InsufficientTokenReserve(_outcome, _amountTokenToBuy);
        }

        // Check if ETH sent matches the exact price
        uint256 expectedPrice = getBuyPriceInEth(_outcome, _amountTokenToBuy);
        if (msg.value != expectedPrice) {
            revert PredictionMarket__MustSendExactETHAmount();
        }

        // Update trading revenue
        s_lpTradingRevenue += msg.value;

        // Transfer tokens to buyer
        bool success = targetToken.transfer(msg.sender, _amountTokenToBuy);
        if (!success) {
            revert PredictionMarket__TokenTransferFailed();
        }

        emit TokensPurchased(msg.sender, _outcome, _amountTokenToBuy, msg.value);
    }

    /**
     * @notice Sell prediction outcome tokens for ETH, need to call priceInETH function first to get right amount of tokens to buy
     * @param _outcome The possible outcome (YES or NO) to sell tokens for
     * @param _tradingAmount The amount of tokens to sell
     */
    function sellTokensForEth(Outcome _outcome, uint256 _tradingAmount) external predictionNotReported amountGreaterThanZero(_tradingAmount) notOwner {
        /// Checkpoint 8 ////
        PredictionMarketToken targetToken = _outcome == Outcome.YES ? i_yesToken : i_noToken;

        // Check if user has enough tokens to sell
        if (_tradingAmount > targetToken.balanceOf(msg.sender)) {
            revert PredictionMarket__InsufficientBalance(_tradingAmount, targetToken.balanceOf(msg.sender));
        }

        // Check if user has approved the contract to transfer their tokens
        if (_tradingAmount > targetToken.allowance(msg.sender, address(this))) {
            revert PredictionMarket__InsufficientAllowance(_tradingAmount, targetToken.allowance(msg.sender, address(this)));
        }

        // Calculate ETH to pay using sell price
        uint256 ethToPay = getSellPriceInEth(_outcome, _tradingAmount);

        // Check if contract has enough ETH to pay out
        if (ethToPay > s_lpTradingRevenue) {
            revert PredictionMarket__InsufficientLiquidity();
        }

        // Deduct ETH from trading revenue
        s_lpTradingRevenue -= ethToPay;

        // Transfer tokens from user to contract
        bool transferSuccess = targetToken.transferFrom(msg.sender, address(this), _tradingAmount);
        if (!transferSuccess) {
            revert PredictionMarket__TokenTransferFailed();
        }

        // Transfer ETH to seller
        (bool ethSuccess, ) = payable(msg.sender).call{value: ethToPay}("");
        if (!ethSuccess) {
            revert PredictionMarket__ETHTransferFailed();
        }

        emit TokensSold(msg.sender, _outcome, _tradingAmount, ethToPay);
    }

    /**
     * @notice Redeem winning tokens for ETH after prediction is resolved, winning tokens are burned and user receives ETH
     * @dev Only if the prediction is resolved
     * @param _amount The amount of winning tokens to redeem
     */
    function redeemWinningTokens(uint256 _amount) external predictionReported amountGreaterThanZero(_amount) notOwner {
        /// Checkpoint 9 ////
        // Check if user has winning tokens to redeem
        uint256 userWinningTokens = s_winningToken.balanceOf(msg.sender);
        if (_amount > userWinningTokens) {
            revert PredictionMarket__InsufficientWinningTokens();
        }

        // Calculate ETH payout based on winning tokens
        uint256 ethPayout = (_amount * i_initialTokenValue) / PRECISION;

        // Check if contract has enough ETH collateral to pay out
        if (ethPayout > s_ethCollateral) {
            revert PredictionMarket__InsufficientLiquidity();
        }

        // Subtract from collateral
        s_ethCollateral -= ethPayout;

        // Burn the winning tokens from user
        s_winningToken.burn(msg.sender, _amount);

        // Transfer ETH to user
        (bool success, ) = payable(msg.sender).call{value: ethPayout}("");
        if (!success) {
            revert PredictionMarket__ETHTransferFailed();
        }

        emit WinningTokensRedeemed(msg.sender, _amount, ethPayout);
    }

    /**
     * @notice Calculate the total ETH price for buying tokens
     * @param _outcome The possible outcome (YES or NO) to buy tokens for
     * @param _tradingAmount The amount of tokens to buy
     * @return The total ETH price
     */
    function getBuyPriceInEth(Outcome _outcome, uint256 _tradingAmount) public view returns (uint256) {
        /// Checkpoint 7 ////
        return _calculatePriceInEth(_outcome, _tradingAmount, false);
    }

    /**
     * @notice Calculate the total ETH price for selling tokens
     * @param _outcome The possible outcome (YES or NO) to sell tokens for
     * @param _tradingAmount The amount of tokens to sell
     * @return The total ETH price
     */
    function getSellPriceInEth(Outcome _outcome, uint256 _tradingAmount) public view returns (uint256) {
        /// Checkpoint 7 ////
        return _calculatePriceInEth(_outcome, _tradingAmount, true);
    }

    /////////////////////////
    /// Helper Functions ///
    ////////////////////////

    /**
     * @dev Internal helper to calculate ETH price for both buying and selling
     * @param _outcome The possible outcome (YES or NO)
     * @param _tradingAmount The amount of tokens
     * @param _isSelling Whether this is a sell calculation
     */
    function _calculatePriceInEth(
        Outcome _outcome,
        uint256 _tradingAmount,
        bool _isSelling
    ) private view returns (uint256) {
        /// Checkpoint 7 ////
        if (_tradingAmount == 0) {
            return 0;
        }

        // Get current reserves
        (uint256 targetReserve, uint256 otherReserve) = _getCurrentReserves(_outcome);

        // Calculate current tokens sold (total supply - current reserve)
        uint256 targetTotalSupply = _outcome == Outcome.YES ? i_yesToken.totalSupply() : i_noToken.totalSupply();
        uint256 otherTotalSupply = _outcome == Outcome.YES ? i_noToken.totalSupply() : i_yesToken.totalSupply();

        uint256 targetTokensSold = targetTotalSupply - targetReserve;
        uint256 otherTokensSold = otherTotalSupply - otherReserve;

        // Calculate probability before trade (locked tokens already reflected in the sold amounts)
        uint256 totalSoldBefore = targetTokensSold + otherTokensSold;
        uint256 probabilityBefore = _calculateProbability(targetTokensSold, totalSoldBefore);

        // Calculate probability after trade
        uint256 targetSoldAfter;
        uint256 totalSoldAfter;
        if (_isSelling) {
            // Selling reduces tokens sold (increases reserve)
            if (targetTokensSold >= _tradingAmount) {
                targetSoldAfter = targetTokensSold - _tradingAmount;
                totalSoldAfter = totalSoldBefore - _tradingAmount;
            } else {
                revert PredictionMarket__InsufficientTokenReserve(_outcome, _tradingAmount);
            }
        } else {
            // Buying increases tokens sold (decreases reserve)
            if (targetReserve >= _tradingAmount) {
                targetSoldAfter = targetTokensSold + _tradingAmount;
                totalSoldAfter = totalSoldBefore + _tradingAmount;
            } else {
                revert PredictionMarket__InsufficientLiquidity();
            }
        }

        uint256 probabilityAfter = _calculateProbability(targetSoldAfter, totalSoldAfter);

        // Calculate average probability
        uint256 probabilityAvg = (probabilityBefore + probabilityAfter) / 2;

        // Calculate price: initialTokenValue * probabilityAvg * tradingAmount
        return (i_initialTokenValue * probabilityAvg * _tradingAmount) / (PRECISION * PRECISION);
    }

    /**
     * @dev Internal helper to get the current reserves of the tokens
     * @param _outcome The possible outcome (YES or NO)
     * @return The current reserves of the tokens
     */
    function _getCurrentReserves(Outcome _outcome) private view returns (uint256, uint256) {
        /// Checkpoint 7 ////
        uint256 yesReserve = i_yesToken.balanceOf(address(this));
        uint256 noReserve = i_noToken.balanceOf(address(this));

        if (_outcome == Outcome.YES) {
            return (yesReserve, noReserve);
        } else {
            return (noReserve, yesReserve);
        }
    }

    /**
     * @dev Internal helper to calculate the probability of the tokens
     * @param tokensSold The number of tokens sold
     * @param totalSold The total number of tokens sold
     * @return The probability of the tokens
     */
    function _calculateProbability(uint256 tokensSold, uint256 totalSold) private pure returns (uint256) {
        /// Checkpoint 7 ////
        if (totalSold == 0) {
            return 0;
        }
        return (tokensSold * PRECISION) / totalSold;
    }

    /////////////////////////
    /// Getter Functions ///
    ////////////////////////

    /**
     * @notice Get the prediction details
     */
    function getPrediction()
        external
        view
        returns (
            string memory question,
            string memory outcome1,
            string memory outcome2,
            address oracle,
            uint256 initialTokenValue,
            uint256 yesTokenReserve,
            uint256 noTokenReserve,
            bool isReported,
            address yesToken,
            address noToken,
            address winningToken,
            uint256 ethCollateral,
            uint256 lpTradingRevenue,
            address predictionMarketOwner,
            uint256 initialProbability,
            uint256 percentageLocked
        )
    {
        /// Checkpoint 3 ////
        oracle = i_oracle;
        initialTokenValue = i_initialTokenValue;
        percentageLocked = i_percentageLocked;
        initialProbability = i_initialYesProbability;
        question = s_question;
        ethCollateral = s_ethCollateral;
        lpTradingRevenue = s_lpTradingRevenue;
        predictionMarketOwner = owner();
        yesToken = address(i_yesToken);
        noToken = address(i_noToken);
        outcome1 = i_yesToken.name();
        outcome2 = i_noToken.name();
        yesTokenReserve = i_yesToken.balanceOf(address(this));
        noTokenReserve = i_noToken.balanceOf(address(this));
        /// Checkpoint 5 ////
        isReported = s_isReported;
        winningToken = address(s_winningToken);
    }
}

contracts/PredictionMarketAMM.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import { IERC20 } from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import { IERC1155 } from "@openzeppelin/contracts/token/ERC1155/IERC1155.sol";
import { IERC1155Receiver } from "@openzeppelin/contracts/token/ERC1155/IERC1155Receiver.sol";
import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";
import { ReentrancyGuard } from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import { ConditionalTokens } from "./ConditionalTokens.sol";

/**
 * @title PredictionMarketAMM
 * @notice AMM for trading YES/NO ERC-1155 CTF outcome tokens.
 *
 * @dev This contract preserves the core probability-weighted pricing logic from the original
 *      speedrun-ethereum PredictionMarket.sol but adapts it to:
 *       - Trade ERC-1155 CTF positions instead of ERC-20 tokens
 *       - Use USDC (ERC-20) as collateral instead of ETH
 *       - Support multiple markets (pools) without deploying a new contract per market
 *       - Disable trading after the CTF condition is resolved
 *
 * PRICING ALGORITHM (preserved from original):
 *  Buy/Sell price = initialTokenValue × avgProbability × amount
 *  Where probability = targetTokensSold / totalTokensSold for both outcomes
 *  avgProbability = (probabilityBefore + probabilityAfter) / 2
 *
 * Each pool is identified by a `conditionId` derived from the CTF:
 *  conditionId = keccak256(adapter, questionId, outcomeSlotCount)
 */
contract PredictionMarketAMM is Ownable, ReentrancyGuard, IERC1155Receiver {
    ////////////////////////////////////////////////////
    // Constants
    ////////////////////////////////////////////////////

    uint256 private constant PRECISION = 1e18;

    ////////////////////////////////////////////////////
    // Types
    ////////////////////////////////////////////////////

    struct Pool {
        uint256 yesTokenId;        // ERC-1155 positionId for YES outcome
        uint256 noTokenId;         // ERC-1155 positionId for NO outcome
        uint256 yesReserve;        // YES token balance held by this AMM
        uint256 noReserve;         // NO token balance held by this AMM
        uint256 usdcCollateral;    // Total USDC backing this pool
        uint256 lpTradingRevenue;  // Accumulated USDC from buy/sell spreads
        uint256 initialTokenValue; // USDC value of one token unit (precision-scaled, e.g. 1e6 for $1 USDC)
        uint256 initialYesProbability; // Starting YES probability (1-99)
        uint256 percentageLocked;  // % of supply locked by LP to set initial probability (1-99)
        address lpOwner;           // Address that seeded liquidity
        bool resolved;             // True after CTF condition is resolved
        bool exists;
    }

    ////////////////////////////////////////////////////
    // State
    ////////////////////////////////////////////////////

    /// @notice The Gnosis CTF contract
    ConditionalTokens public immutable ctf;

    /// @notice The collateral ERC-20 (USDC on Sepolia: 0x1c7D4B196Cb0C7B01d743Fbc6116a902379C7238)
    IERC20 public immutable collateral;

    /// @notice conditionId → Pool
    mapping(bytes32 => Pool) public pools;

    /// @notice List of all conditionIds for enumeration
    bytes32[] public allPools;

    ////////////////////////////////////////////////////
    // Events
    ////////////////////////////////////////////////////

    event PoolCreated(bytes32 indexed conditionId, uint256 yesTokenId, uint256 noTokenId, uint256 usdcCollateral);
    event LiquidityAdded(bytes32 indexed conditionId, address indexed provider, uint256 usdcAmount, uint256 tokenAmount);
    event LiquidityRemoved(bytes32 indexed conditionId, address indexed provider, uint256 usdcAmount, uint256 tokenAmount);
    event TokensBought(bytes32 indexed conditionId, address indexed buyer, uint256 outcome, uint256 tokenAmount, uint256 usdcPaid);
    event TokensSold(bytes32 indexed conditionId, address indexed seller, uint256 outcome, uint256 tokenAmount, uint256 usdcReceived);
    event PoolResolved(bytes32 indexed conditionId);

    ////////////////////////////////////////////////////
    // Errors
    ////////////////////////////////////////////////////

    error PoolAlreadyExists(bytes32 conditionId);
    error PoolNotFound(bytes32 conditionId);
    error PoolResolved_();
    error PoolNotResolved();
    error InsufficientReserve(uint256 outcome, uint256 requested);
    error InsufficientLiquidity();
    error InsufficientBalance(uint256 requested, uint256 available);
    error InvalidProbability();
    error InvalidPercentage();
    error AmountZero();
    error WrongUsdcAmount();
    error NotLPOwner();
    error TransferFailed();
    error OnlyFromCTF();

    ////////////////////////////////////////////////////
    // Modifiers
    ////////////////////////////////////////////////////

    modifier poolExists(bytes32 conditionId) {
        if (!pools[conditionId].exists) revert PoolNotFound(conditionId);
        _;
    }

    modifier notResolved(bytes32 conditionId) {
        if (pools[conditionId].resolved) revert PoolResolved_();
        _;
    }

    ////////////////////////////////////////////////////
    // Constructor
    ////////////////////////////////////////////////////

    constructor(address _ctf, address _collateral) Ownable(msg.sender) {
        ctf = ConditionalTokens(_ctf);
        collateral = IERC20(_collateral);
    }

    ////////////////////////////////////////////////////
    // Pool Management
    ////////////////////////////////////////////////////

    /**
     * @notice Creates an AMM pool for a CTF binary market and seeds initial liquidity.
     * @dev Caller must have already approved this contract to spend `usdcAmount` USDC.
     *      The USDC is split-positioned into YES/NO ERC-1155 tokens by the CTF;
     *      then deposited into the pool as reserves.
     *
     * @param conditionId         The CTF conditionId derived from keccak256(adapter, questionId, 2).
     * @param yesTokenId          ERC-1155 YES positionId from the CTF.
     * @param noTokenId           ERC-1155 NO positionId from the CTF.
     * @param usdcAmount          Amount of USDC to provide as initial liquidity.
     * @param initialTokenValue   USDC value (in 6-decimal USDC units) per 1e18 outcome tokens (~= $1.00).
     * @param initialYesProbability Starting YES probability (1-99).
     * @param percentageToLock    % of token supply locked to simulate initial probability (1-99).
     */
    function createPool(
        bytes32 conditionId,
        uint256 yesTokenId,
        uint256 noTokenId,
        uint256 usdcAmount,
        uint256 initialTokenValue,
        uint8 initialYesProbability,
        uint8 percentageToLock
    ) external nonReentrant {
        if (pools[conditionId].exists) revert PoolAlreadyExists(conditionId);
        if (usdcAmount == 0) revert AmountZero();
        if (initialYesProbability == 0 || initialYesProbability >= 100) revert InvalidProbability();
        if (percentageToLock == 0 || percentageToLock >= 100) revert InvalidPercentage();

        // Pull USDC from caller
        if (!collateral.transferFrom(msg.sender, address(this), usdcAmount)) revert TransferFailed();

        // Split USDC → YES + NO ERC-1155 tokens via the CTF
        collateral.approve(address(ctf), usdcAmount);
        uint256[] memory partition = new uint256[](2);
        partition[0] = 1; // indexSet for YES (bit 0)
        partition[1] = 2; // indexSet for NO  (bit 1)
        ctf.splitPosition(collateral, bytes32(0), conditionId, partition, usdcAmount);

        // Calculate initial token amount
        uint256 tokenAmount = (usdcAmount * PRECISION) / initialTokenValue;

        // Calculate locked tokens to simulate initial probability
        uint256 lockedYes = (tokenAmount * initialYesProbability * percentageToLock * 2) / 10000;
        uint256 lockedNo  = (tokenAmount * (100 - initialYesProbability) * percentageToLock * 2) / 10000;

        // Pool holds the non-locked tokens as reserves
        uint256 yesReserve = tokenAmount - lockedYes;
        uint256 noReserve  = tokenAmount - lockedNo;

        // Transfer locked tokens to LP owner (held off-AMM, simulating initial probability)
        ctf.safeTransferFrom(address(this), msg.sender, yesTokenId, lockedYes, "");
        ctf.safeTransferFrom(address(this), msg.sender, noTokenId,  lockedNo,  "");

        pools[conditionId] = Pool({
            yesTokenId:            yesTokenId,
            noTokenId:             noTokenId,
            yesReserve:            yesReserve,
            noReserve:             noReserve,
            usdcCollateral:        usdcAmount,
            lpTradingRevenue:      0,
            initialTokenValue:     initialTokenValue,
            initialYesProbability: initialYesProbability,
            percentageLocked:      percentageToLock,
            lpOwner:               msg.sender,
            resolved:              false,
            exists:                true
        });

        allPools.push(conditionId);

        emit PoolCreated(conditionId, yesTokenId, noTokenId, usdcAmount);
    }

    /**
     * @notice LP owner adds more liquidity to an existing pool.
     */
    function addLiquidity(bytes32 conditionId, uint256 usdcAmount)
        external
        nonReentrant
        poolExists(conditionId)
        notResolved(conditionId)
    {
        Pool storage pool = pools[conditionId];
        if (msg.sender != pool.lpOwner) revert NotLPOwner();
        if (usdcAmount == 0) revert AmountZero();

        if (!collateral.transferFrom(msg.sender, address(this), usdcAmount)) revert TransferFailed();

        collateral.approve(address(ctf), usdcAmount);
        uint256[] memory partition = new uint256[](2);
        partition[0] = 1;
        partition[1] = 2;
        ctf.splitPosition(collateral, bytes32(0), conditionId, partition, usdcAmount);

        uint256 additionalTokens = (usdcAmount * PRECISION) / pool.initialTokenValue;
        pool.yesReserve    += additionalTokens;
        pool.noReserve     += additionalTokens;
        pool.usdcCollateral += usdcAmount;

        emit LiquidityAdded(conditionId, msg.sender, usdcAmount, additionalTokens);
    }

    /**
     * @notice LP owner removes liquidity from an existing pool.
     */
    function removeLiquidity(bytes32 conditionId, uint256 usdcAmount)
        external
        nonReentrant
        poolExists(conditionId)
        notResolved(conditionId)
    {
        Pool storage pool = pools[conditionId];
        if (msg.sender != pool.lpOwner) revert NotLPOwner();
        if (usdcAmount == 0) revert AmountZero();
        if (usdcAmount > pool.usdcCollateral) revert InsufficientLiquidity();

        uint256 tokensToRemove = (usdcAmount * PRECISION) / pool.initialTokenValue;
        if (tokensToRemove > pool.yesReserve) revert InsufficientReserve(0, tokensToRemove);
        if (tokensToRemove > pool.noReserve)  revert InsufficientReserve(1, tokensToRemove);

        pool.yesReserve     -= tokensToRemove;
        pool.noReserve      -= tokensToRemove;
        pool.usdcCollateral -= usdcAmount;

        // Merge YES+NO tokens back into USDC via CTF
        _approveERC1155ForCTF();
        uint256[] memory partition = new uint256[](2);
        partition[0] = 1;
        partition[1] = 2;
        ctf.mergePositions(collateral, bytes32(0), conditionId, partition, tokensToRemove);

        if (!collateral.transfer(msg.sender, usdcAmount)) revert TransferFailed();

        emit LiquidityRemoved(conditionId, msg.sender, usdcAmount, tokensToRemove);
    }

    /**
     * @notice LP owner withdraws liquidity + trading revenue after resolution.
     */
    function withdrawAfterResolution(bytes32 conditionId)
        external
        nonReentrant
        poolExists(conditionId)
    {
        Pool storage pool = pools[conditionId];
        if (msg.sender != pool.lpOwner) revert NotLPOwner();
        if (!pool.resolved) revert PoolNotResolved();

        uint256 revenue = pool.lpTradingRevenue;
        pool.lpTradingRevenue = 0;

        if (revenue > 0) {
            if (!collateral.transfer(msg.sender, revenue)) revert TransferFailed();
        }
        // YES/NO reserve positions held by this AMM are redeemed via CTF.redeemPositions by LP separately
    }

    ////////////////////////////////////////////////////
    // Trading
    ////////////////////////////////////////////////////

    /**
     * @notice Buys outcome tokens with USDC.
     * @dev Caller must have approved this contract for `maxUsdcIn` USDC.
     * @param conditionId    The pool's conditionId.
     * @param outcome        0 = YES, 1 = NO.
     * @param tokenAmount    Number of outcome tokens to buy (18 decimals).
     * @param maxUsdcIn      Maximum USDC willing to pay (slippage protection).
     */
    function buyTokens(
        bytes32 conditionId,
        uint256 outcome,
        uint256 tokenAmount,
        uint256 maxUsdcIn
    ) external nonReentrant poolExists(conditionId) notResolved(conditionId) {
        if (tokenAmount == 0) revert AmountZero();
        Pool storage pool = pools[conditionId];

        uint256 usdcCost = getBuyPrice(conditionId, outcome, tokenAmount);
        if (usdcCost > maxUsdcIn) revert WrongUsdcAmount();

        // Check reserve
        (uint256 targetReserve,) = _getReserves(pool, outcome);
        if (tokenAmount > targetReserve) revert InsufficientReserve(outcome, tokenAmount);

        // Collect USDC from buyer
        if (!collateral.transferFrom(msg.sender, address(this), usdcCost)) revert TransferFailed();
        pool.lpTradingRevenue += usdcCost;

        // Deduct from reserve
        if (outcome == 0) pool.yesReserve -= tokenAmount;
        else                pool.noReserve  -= tokenAmount;

        // Transfer outcome tokens to buyer
        uint256 tokenId = outcome == 0 ? pool.yesTokenId : pool.noTokenId;
        ctf.safeTransferFrom(address(this), msg.sender, tokenId, tokenAmount, "");

        emit TokensBought(conditionId, msg.sender, outcome, tokenAmount, usdcCost);
    }

    /**
     * @notice Sells outcome tokens for USDC.
     * @dev Caller must have called ctf.setApprovalForAll(ammAddress, true) first.
     * @param conditionId   The pool's conditionId.
     * @param outcome       0 = YES, 1 = NO.
     * @param tokenAmount   Number of outcome tokens to sell.
     * @param minUsdcOut    Minimum USDC to receive (slippage protection).
     */
    function sellTokens(
        bytes32 conditionId,
        uint256 outcome,
        uint256 tokenAmount,
        uint256 minUsdcOut
    ) external nonReentrant poolExists(conditionId) notResolved(conditionId) {
        if (tokenAmount == 0) revert AmountZero();
        Pool storage pool = pools[conditionId];

        uint256 usdcPayout = getSellPrice(conditionId, outcome, tokenAmount);
        if (usdcPayout < minUsdcOut) revert InsufficientLiquidity();
        if (usdcPayout > pool.lpTradingRevenue) revert InsufficientLiquidity();

        // Receive outcome tokens from seller
        uint256 tokenId = outcome == 0 ? pool.yesTokenId : pool.noTokenId;
        ctf.safeTransferFrom(msg.sender, address(this), tokenId, tokenAmount, "");

        pool.lpTradingRevenue -= usdcPayout;
        if (outcome == 0) pool.yesReserve += tokenAmount;
        else               pool.noReserve  += tokenAmount;

        if (!collateral.transfer(msg.sender, usdcPayout)) revert TransferFailed();

        emit TokensSold(conditionId, msg.sender, outcome, tokenAmount, usdcPayout);
    }

    ////////////////////////////////////////////////////
    // Resolution Hook
    ////////////////////////////////////////////////////

    /**
     * @notice Marks a pool as resolved so trading is disabled.
     * @dev Anyone can call this once the CTF condition has been resolved.
     *      The actual payout distribution happens via ctf.redeemPositions().
     */
    function markResolved(bytes32 conditionId) external poolExists(conditionId) {
        Pool storage pool = pools[conditionId];
        if (pool.resolved) return;
        // Verify CTF has resolved: payoutDenominator > 0
        require(ctf.payoutDenominator(conditionId) > 0, "AMM: CTF not resolved yet");
        pool.resolved = true;
        emit PoolResolved(conditionId);
    }

    ////////////////////////////////////////////////////
    // Price View Functions (preserve original algorithm)
    ////////////////////////////////////////////////////

    /**
     * @notice Calculate USDC cost to buy `tokenAmount` outcome tokens.
     *  Preserves the original probability-weighted price model.
     */
    function getBuyPrice(bytes32 conditionId, uint256 outcome, uint256 tokenAmount)
        public
        view
        poolExists(conditionId)
        returns (uint256)
    {
        return _calculatePrice(conditionId, outcome, tokenAmount, false);
    }

    /**
     * @notice Calculate USDC received for selling `tokenAmount` outcome tokens.
     */
    function getSellPrice(bytes32 conditionId, uint256 outcome, uint256 tokenAmount)
        public
        view
        poolExists(conditionId)
        returns (uint256)
    {
        return _calculatePrice(conditionId, outcome, tokenAmount, true);
    }

    /**
     * @notice Returns current implied probability of YES outcome (scaled by PRECISION).
     */
    function getYesProbability(bytes32 conditionId) external view poolExists(conditionId) returns (uint256) {
        Pool storage pool = pools[conditionId];
        // Total supply per token side = initial supply at pool creation
        // (approximated from usdcCollateral / initialTokenValue; not stored separately to save gas)
        // Probability ≈ yesSold / (yesSold + noSold)
        uint256 totalSupplyApprox = (pool.usdcCollateral * PRECISION) / pool.initialTokenValue;
        uint256 yesSold = totalSupplyApprox - pool.yesReserve;
        uint256 noSold  = totalSupplyApprox - pool.noReserve;
        uint256 total   = yesSold + noSold;
        if (total == 0) return PRECISION / 2;
        return (yesSold * PRECISION) / total;
    }

    ////////////////////////////////////////////////////
    // Internal Pricing (preserved from original AMM)
    ////////////////////////////////////////////////////

    function _calculatePrice(
        bytes32 conditionId,
        uint256 outcome,
        uint256 tradingAmount,
        bool isSelling
    ) private view returns (uint256) {
        if (tradingAmount == 0) return 0;

        Pool storage pool = pools[conditionId];
        (uint256 targetReserve, uint256 otherReserve) = _getReserves(pool, outcome);

        // Approximate total supply from collateral
        uint256 totalSupply = (pool.usdcCollateral * PRECISION) / pool.initialTokenValue;

        uint256 targetSold = totalSupply - targetReserve;
        uint256 otherSold  = totalSupply - otherReserve;

        uint256 totalSoldBefore = targetSold + otherSold;
        uint256 probabilityBefore = _probability(targetSold, totalSoldBefore);

        uint256 targetSoldAfter;
        uint256 totalSoldAfter;

        if (isSelling) {
            if (targetSold < tradingAmount) revert InsufficientReserve(outcome, tradingAmount);
            targetSoldAfter = targetSold - tradingAmount;
            totalSoldAfter  = totalSoldBefore - tradingAmount;
        } else {
            if (targetReserve < tradingAmount) revert InsufficientReserve(outcome, tradingAmount);
            targetSoldAfter = targetSold + tradingAmount;
            totalSoldAfter  = totalSoldBefore + tradingAmount;
        }

        uint256 probabilityAfter = _probability(targetSoldAfter, totalSoldAfter);
        uint256 probabilityAvg   = (probabilityBefore + probabilityAfter) / 2;

        return (pool.initialTokenValue * probabilityAvg * tradingAmount) / (PRECISION * PRECISION);
    }

    function _getReserves(Pool storage pool, uint256 outcome)
        private
        view
        returns (uint256 targetReserve, uint256 otherReserve)
    {
        if (outcome == 0) return (pool.yesReserve, pool.noReserve);
        return (pool.noReserve, pool.yesReserve);
    }

    function _probability(uint256 sold, uint256 total) private pure returns (uint256) {
        if (total == 0) return 0;
        return (sold * PRECISION) / total;
    }

    ////////////////////////////////////////////////////
    // ERC-1155 Receiver
    ////////////////////////////////////////////////////

    function _approveERC1155ForCTF() private {
        // CTF needs approval to burn position tokens during mergePositions
        if (!IERC1155(address(ctf)).isApprovedForAll(address(this), address(ctf))) {
            IERC1155(address(ctf)).setApprovalForAll(address(ctf), true);
        }
    }

    function onERC1155Received(address, address, uint256, uint256, bytes calldata)
        external
        pure
        override
        returns (bytes4)
    {
        return IERC1155Receiver.onERC1155Received.selector;
    }

    function onERC1155BatchReceived(address, address, uint256[] calldata, uint256[] calldata, bytes calldata)
        external
        pure
        override
        returns (bytes4)
    {
        return IERC1155Receiver.onERC1155BatchReceived.selector;
    }

    function supportsInterface(bytes4 interfaceId) external pure override returns (bool) {
        return interfaceId == type(IERC1155Receiver).interfaceId;
    }

    ////////////////////////////////////////////////////
    // View
    ////////////////////////////////////////////////////

    function getPool(bytes32 conditionId) external view returns (Pool memory) {
        return pools[conditionId];
    }

    function getAllPools() external view returns (bytes32[] memory) {
        return allPools;
    }
}

contracts/PredictionMarketToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity >=0.8.0 <0.9.0;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";

contract PredictionMarketToken is ERC20 {
    error PredictionMarketToken__OnlyPredictionMarketCanMint();
    error PredictionMarketToken__OnlyPredictionMarketCanBurn();
    error PredictionMarketToken__LiquidityProviderCantTransfer();

    address public predictionMarket;
    address public liquidityProvider;

    constructor(
        string memory name,
        string memory symbol,
        address _liquidityProvider,
        uint256 initialSupply
    ) ERC20(name, symbol) {
        predictionMarket = msg.sender;
        liquidityProvider = _liquidityProvider;
        _mint(msg.sender, initialSupply);
    }

    function mint(address to, uint256 amount) external {
        if (msg.sender != predictionMarket) {
            revert PredictionMarketToken__OnlyPredictionMarketCanMint();
        }
        _mint(to, amount);
    }

    function burn(address from, uint256 amount) external {
        if (msg.sender != predictionMarket) {
            revert PredictionMarketToken__OnlyPredictionMarketCanBurn();
        }
        _burn(from, amount);
    }

    function transfer(address to, uint256 amount) public override returns (bool) {
        if (msg.sender == liquidityProvider) {
            revert PredictionMarketToken__LiquidityProviderCantTransfer();
        }
        return super.transfer(to, amount);
    }

    function transferFrom(address from, address to, uint256 amount) public override returns (bool) {
        if (from == liquidityProvider) {
            revert PredictionMarketToken__LiquidityProviderCantTransfer();
        }
        return super.transferFrom(from, to, amount);
    }
}

contracts/ReceiverTemplate.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import { IERC165 } from "@openzeppelin/contracts/interfaces/IERC165.sol";
import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title IReceiver
 * @notice Interface for CRE report receivers.
 */
interface IReceiver is IERC165 {
    function onReport(bytes calldata metadata, bytes calldata report) external;
}

/**
 * @title ReceiverTemplate
 * @notice Abstract base contract for receiving Chainlink CRE workflow reports.
 * @dev Copied verbatim structure from cre-gcp-prediction-market-demo with AiCTFAdapter customisation.
 *      Forwarder address is required; optional workflow identity checks enforce which CRE job can call.
 */
abstract contract ReceiverTemplate is IReceiver, Ownable {
    // Required — set at construction; only this address may call onReport
    address private s_forwarderAddress;

    // Optional identity guards (all zero = disabled)
    address private s_expectedAuthor;
    bytes10 private s_expectedWorkflowName;
    bytes32 private s_expectedWorkflowId;

    bytes private constant HEX_CHARS = "0123456789abcdef";

    error InvalidForwarderAddress();
    error InvalidSender(address sender, address expected);
    error InvalidAuthor(address received, address expected);
    error InvalidWorkflowName(bytes10 received, bytes10 expected);
    error InvalidWorkflowId(bytes32 received, bytes32 expected);
    error WorkflowNameRequiresAuthorValidation();

    event ForwarderAddressUpdated(address indexed previousForwarder, address indexed newForwarder);
    event ExpectedAuthorUpdated(address indexed previousAuthor, address indexed newAuthor);
    event ExpectedWorkflowNameUpdated(bytes10 indexed previousName, bytes10 indexed newName);
    event ExpectedWorkflowIdUpdated(bytes32 indexed previousId, bytes32 indexed newId);
    event SecurityWarning(string message);

    constructor(address _forwarderAddress) Ownable(msg.sender) {
        if (_forwarderAddress == address(0)) revert InvalidForwarderAddress();
        s_forwarderAddress = _forwarderAddress;
        emit ForwarderAddressUpdated(address(0), _forwarderAddress);
    }

    /// @inheritdoc IReceiver
    function onReport(bytes calldata metadata, bytes calldata report) external override {
        if (s_forwarderAddress != address(0) && msg.sender != s_forwarderAddress) {
            revert InvalidSender(msg.sender, s_forwarderAddress);
        }

        if (
            s_expectedWorkflowId != bytes32(0) ||
            s_expectedAuthor != address(0) ||
            s_expectedWorkflowName != bytes10(0)
        ) {
            (bytes32 workflowId, bytes10 workflowName, address workflowOwner) = _decodeMetadata(metadata);

            if (s_expectedWorkflowId != bytes32(0) && workflowId != s_expectedWorkflowId) {
                revert InvalidWorkflowId(workflowId, s_expectedWorkflowId);
            }
            if (s_expectedAuthor != address(0) && workflowOwner != s_expectedAuthor) {
                revert InvalidAuthor(workflowOwner, s_expectedAuthor);
            }
            if (s_expectedWorkflowName != bytes10(0)) {
                if (s_expectedAuthor == address(0)) revert WorkflowNameRequiresAuthorValidation();
                if (workflowName != s_expectedWorkflowName) {
                    revert InvalidWorkflowName(workflowName, s_expectedWorkflowName);
                }
            }
        }

        _processReport(report);
    }

    function getForwarderAddress() external view returns (address) { return s_forwarderAddress; }
    function getExpectedAuthor() external view returns (address) { return s_expectedAuthor; }
    function getExpectedWorkflowName() external view returns (bytes10) { return s_expectedWorkflowName; }
    function getExpectedWorkflowId() external view returns (bytes32) { return s_expectedWorkflowId; }

    function setForwarderAddress(address _forwarder) external onlyOwner {
        address prev = s_forwarderAddress;
        if (_forwarder == address(0)) emit SecurityWarning("Forwarder set to zero - INSECURE");
        s_forwarderAddress = _forwarder;
        emit ForwarderAddressUpdated(prev, _forwarder);
    }

    function setExpectedAuthor(address _author) external onlyOwner {
        address prev = s_expectedAuthor;
        s_expectedAuthor = _author;
        emit ExpectedAuthorUpdated(prev, _author);
    }

    function setExpectedWorkflowName(string calldata _name) external onlyOwner {
        bytes10 prev = s_expectedWorkflowName;
        if (bytes(_name).length == 0) {
            s_expectedWorkflowName = bytes10(0);
            emit ExpectedWorkflowNameUpdated(prev, bytes10(0));
            return;
        }
        bytes32 hash = sha256(bytes(_name));
        bytes memory hex_ = _bytesToHexString(abi.encodePacked(hash));
        bytes memory first10 = new bytes(10);
        for (uint256 i = 0; i < 10; i++) first10[i] = hex_[i];
        s_expectedWorkflowName = bytes10(first10);
        emit ExpectedWorkflowNameUpdated(prev, s_expectedWorkflowName);
    }

    function setExpectedWorkflowId(bytes32 _id) external onlyOwner {
        bytes32 prev = s_expectedWorkflowId;
        s_expectedWorkflowId = _id;
        emit ExpectedWorkflowIdUpdated(prev, _id);
    }

    function _bytesToHexString(bytes memory data) private pure returns (bytes memory) {
        bytes memory hex_ = new bytes(data.length * 2);
        for (uint256 i = 0; i < data.length; i++) {
            hex_[i * 2]     = HEX_CHARS[uint8(data[i] >> 4)];
            hex_[i * 2 + 1] = HEX_CHARS[uint8(data[i] & 0x0f)];
        }
        return hex_;
    }

    function _decodeMetadata(bytes memory metadata)
        internal
        pure
        returns (bytes32 workflowId, bytes10 workflowName, address workflowOwner)
    {
        assembly {
            workflowId   := mload(add(metadata, 32))
            workflowName := mload(add(metadata, 64))
            workflowOwner := shr(mul(12, 8), mload(add(metadata, 74)))
        }
    }

    function _processReport(bytes calldata report) internal virtual;

    function supportsInterface(bytes4 interfaceId) public pure virtual override returns (bool) {
        return interfaceId == type(IReceiver).interfaceId || interfaceId == type(IERC165).interfaceId;
    }
}
